class Solution {
public:
    int palindromePartition(string s, int k) {
        int n = s.size();
        vector<vector<int>> dp(n, vector<int>(n));
        for (int i = 0; i < n; ++i) {
            dp[i][i] = 0;
        }
        for (int len = 2; len <= n; ++len) {
            for (int i = 0; i <= n - len; ++i) {
                int j = i + len - 1;
                dp[i][j] = dp[i + 1][j - 1] + (s[i] != s[j]);
            }
        }

        vector<vector<int>> partitions(n + 1, vector<int>(k + 1, INT_MAX));
        partitions[0][0] = 0;
        for (int i = 1; i <= n; ++i) {
            for (int j = 1; j <= min(i, k); ++j) {
                for (int p = 0; p < i; ++p) {
                    partitions[i][j] = min(partitions[i][j], partitions[p][j - 1] + dp[p][i - 1]);
                }
            }
        }
        return partitions[n][k];
    }
};
